import os

def create_files():
    files = {
        "backend/app/controllers/analytics_controller.py": "from fastapi import APIRouter, Depends\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom sqlalchemy.future import select\nfrom sqlalchemy import func, desc\nfrom app.database.session import get_db\nfrom app.models.scan import Scan\nimport time\n\nrouter = APIRouter()\n\n# Simple TTL Cache for the expensive Dashboard Aggregations\nclass DashboardCache:\n    def __init__(self, ttl=60):\n        self.ttl = ttl\n        self.data = None\n        self.last_updated = 0\n        \n    def get(self):\n        if self.data and time.time() - self.last_updated < self.ttl:\n            return self.data\n        return None\n        \n    def set(self, data):\n        self.data = data\n        self.last_updated = time.time()\n\ncache = DashboardCache()\n\n@router.get(\"/api/analytics/dashboard\")\nasync def get_dashboard(db: AsyncSession = Depends(get_db)):\n    cached = cache.get()\n    if cached:\n        return cached\n        \n    # 1. Basic Stats\n    total_scans_result = await db.execute(select(func.count(Scan.id)))\n    total_scans = total_scans_result.scalar() or 0\n    \n    avg_risk_result = await db.execute(select(func.avg(Scan.risk_score)))\n    avg_risk = float(avg_risk_result.scalar() or 0.0)\n    \n    # 2. Risk Distribution\n    levels = await db.execute(select(Scan.risk_level, func.count(Scan.id)).group_by(Scan.risk_level))\n    distribution = {row[0]: row[1] for row in levels.all()}\n    \n    # 3. Daily Trend (Mocked for Demo since extracting date parts varies by dialect)\n    daily_trend = [\n        {\"name\": \"Mon\", \"scans\": total_scans * 0.1},\n        {\"name\": \"Tue\", \"scans\": total_scans * 0.2},\n        {\"name\": \"Wed\", \"scans\": total_scans * 0.15},\n        {\"name\": \"Thu\", \"scans\": total_scans * 0.25},\n        {\"name\": \"Fri\", \"scans\": total_scans * 0.3},\n    ]\n    \n    # 4. Threat Categories (Mocked distributions)\n    threat_categories = [\n        {\"name\": \"Phishing\", \"value\": 45},\n        {\"name\": \"Malware\", \"value\": 30},\n        {\"name\": \"Typosquatting\", \"value\": 25}\n    ]\n    \n    data = {\n        \"total_scans\": total_scans,\n        \"average_risk\": round(avg_risk, 1),\n        \"risk_distribution\": distribution,\n        \"daily_trend\": daily_trend,\n        \"threat_categories\": threat_categories\n    }\n    \n    cache.set(data)\n    return data\n\n@router.get(\"/api/analytics/history\")\nasync def get_history(db: AsyncSession = Depends(get_db)):\n    result = await db.execute(select(Scan).order_by(desc(Scan.created_at)).limit(50))\n    scans = result.scalars().all()\n    return [\n        {\n            \"id\": s.id,\n            \"target\": s.target,\n            \"scan_type\": s.scan_type,\n            \"risk_level\": s.risk_level,\n            \"risk_score\": s.risk_score,\n            \"date\": str(s.created_at)\n        } for s in scans\n    ]\n",
        "backend/app/main.py": "from fastapi import FastAPI\nfrom fastapi.middleware.cors import CORSMiddleware\nfrom app.controllers import auth_controller, scan_controller, report_controller, analytics_controller\nfrom app.middleware.auth import JWTAuthMiddleware\n\napp = FastAPI(title=\"TrustGuardAI Backend\", version=\"1.0.0\")\n\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=[\"http://localhost:3000\"],\n    allow_credentials=True,\n    allow_methods=[\"*\"],\n    allow_headers=[\"*\"],\n)\n\napp.include_router(auth_controller.router, tags=[\"auth\"])\napp.include_router(scan_controller.router, prefix=\"/api/scan\", tags=[\"scans\"])\napp.include_router(report_controller.router, tags=[\"reports\"])\napp.include_router(analytics_controller.router, tags=[\"analytics\"])\n\n@app.get(\"/api/health\")\nasync def health_check():\n    return {\"status\": \"ok\"}\n",
        "frontend/src/pages/Dashboard.tsx": "import React, { useEffect, useState } from 'react';\nimport { motion } from 'framer-motion';\nimport { Activity, ShieldAlert, BarChart3, Clock } from 'lucide-react';\nimport { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';\nimport api from '../utils/axios';\n\nconst COLORS = ['#ef4444', '#f97316', '#eab308', '#22c55e']; // Danger, Warning, Notice, Success\n\nconst Dashboard = () => {\n  const [data, setData] = useState<any>(null);\n\n  useEffect(() => {\n    const fetchData = async () => {\n      try {\n        const res = await api.get('/analytics/dashboard');\n        setData(res.data);\n      } catch (err) {\n        console.error(err);\n      }\n    };\n    fetchData();\n  }, []);\n\n  if (!data) return <div className=\"flex justify-center p-20\"><div className=\"animate-spin rounded-full h-12 w-12 border-t-2 border-primary\"></div></div>;\n\n  const stats = [\n    { label: \"Total Scans\", value: data.total_scans, icon: <Activity className=\"text-blue-400\" /> },\n    { label: \"Average Risk\", value: `${data.average_risk}/100`, icon: <ShieldAlert className=\"text-danger\" /> },\n    { label: \"Critical Threats\", value: data.risk_distribution['Critical'] || 0, icon: <BarChart3 className=\"text-orange-400\" /> },\n    { label: \"Uptime\", value: \"99.9%\", icon: <Clock className=\"text-success\" /> }\n  ];\n\n  return (\n    <div className=\"space-y-8\">\n      <h1 className=\"text-3xl font-bold\">Analytics Dashboard</h1>\n      \n      {/* Top Cards */}\n      <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6\">\n        {stats.map((stat, i) => (\n          <motion.div key={i} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }} className=\"glass-panel p-6 flex items-center gap-4\">\n            <div className=\"p-4 bg-surface rounded-xl\">{stat.icon}</div>\n            <div>\n              <div className=\"text-gray-400 text-sm\">{stat.label}</div>\n              <div className=\"text-2xl font-bold\">{stat.value}</div>\n            </div>\n          </motion.div>\n        ))}\n      </div>\n\n      {/* Charts */}\n      <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-6\">\n        <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.3 }} className=\"glass-panel p-6 lg:col-span-2\">\n          <h3 className=\"text-xl font-bold mb-6\">Scan Volume Trend (7 Days)</h3>\n          <div className=\"h-72\">\n            <ResponsiveContainer width=\"100%\" height=\"100%\">\n              <AreaChart data={data.daily_trend}>\n                <defs>\n                  <linearGradient id=\"colorScans\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                    <stop offset=\"5%\" stopColor=\"#3b82f6\" stopOpacity={0.3}/>\n                    <stop offset=\"95%\" stopColor=\"#3b82f6\" stopOpacity={0}/>\n                  </linearGradient>\n                </defs>\n                <XAxis dataKey=\"name\" stroke=\"#4b5563\" />\n                <YAxis stroke=\"#4b5563\" />\n                <Tooltip contentStyle={{ backgroundColor: '#1f2937', borderColor: '#374151', borderRadius: '8px' }} />\n                <Area type=\"monotone\" dataKey=\"scans\" stroke=\"#3b82f6\" strokeWidth={3} fillOpacity={1} fill=\"url(#colorScans)\" />\n              </AreaChart>\n            </ResponsiveContainer>\n          </div>\n        </motion.div>\n\n        <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.4 }} className=\"glass-panel p-6\">\n          <h3 className=\"text-xl font-bold mb-6\">Threat Distribution</h3>\n          <div className=\"h-72\">\n            <ResponsiveContainer width=\"100%\" height=\"100%\">\n              <PieChart>\n                <Pie data={data.threat_categories} innerRadius={60} outerRadius={80} paddingAngle={5} dataKey=\"value\">\n                  {data.threat_categories.map((entry: any, index: number) => (\n                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />\n                  ))}\n                </Pie>\n                <Tooltip contentStyle={{ backgroundColor: '#1f2937', borderColor: '#374151', borderRadius: '8px' }} />\n              </PieChart>\n            </ResponsiveContainer>\n          </div>\n          <div className=\"flex justify-center gap-4 mt-4 text-sm text-gray-400\">\n             {data.threat_categories.map((c: any, i: number) => (\n               <div key={i} className=\"flex items-center gap-2\">\n                 <div className=\"w-3 h-3 rounded-full\" style={{backgroundColor: COLORS[i]}}></div> {c.name}\n               </div>\n             ))}\n          </div>\n        </motion.div>\n      </div>\n    </div>\n  );\n};\n\nexport default Dashboard;\n",
        "frontend/src/pages/History.tsx": "import React, { useEffect, useState } from 'react';\nimport { Search, Filter, Trash2, ArrowRight } from 'lucide-react';\nimport api from '../utils/axios';\nimport { Link } from 'react-router-dom';\nimport { motion } from 'framer-motion';\n\nconst History = () => {\n  const [history, setHistory] = useState<any[]>([]);\n  const [searchTerm, setSearchTerm] = useState('');\n\n  useEffect(() => {\n    const fetchHistory = async () => {\n      try {\n        const res = await api.get('/analytics/history');\n        setHistory(res.data);\n      } catch (err) {\n        console.error(err);\n      }\n    };\n    fetchHistory();\n  }, []);\n\n  const filtered = history.filter(s => s.target.toLowerCase().includes(searchTerm.toLowerCase()));\n\n  return (\n    <div className=\"space-y-8\">\n      <div className=\"flex flex-col md:flex-row justify-between items-start md:items-center gap-4\">\n        <h1 className=\"text-3xl font-bold\">Scan History</h1>\n        <div className=\"flex gap-4 w-full md:w-auto\">\n          <div className=\"relative flex-1 md:w-64\">\n            <Search className=\"absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 w-4 h-4\" />\n            <input \n              type=\"text\" placeholder=\"Search domains...\" \n              className=\"w-full bg-surface border border-border rounded-lg pl-10 pr-4 py-2 text-sm focus:outline-none focus:border-primary\"\n              value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}\n            />\n          </div>\n          <button className=\"btn-secondary px-4 py-2 flex items-center gap-2 text-sm\"><Filter size={16}/> Filters</button>\n        </div>\n      </div>\n\n      <div className=\"glass-panel overflow-hidden\">\n        <div className=\"overflow-x-auto\">\n          <table className=\"w-full text-left border-collapse\">\n            <thead>\n              <tr className=\"border-b border-border bg-surface/50\">\n                <th className=\"p-4 font-medium text-gray-400\">Target</th>\n                <th className=\"p-4 font-medium text-gray-400\">Type</th>\n                <th className=\"p-4 font-medium text-gray-400\">Risk Score</th>\n                <th className=\"p-4 font-medium text-gray-400\">Level</th>\n                <th className=\"p-4 font-medium text-gray-400\">Date</th>\n                <th className=\"p-4 font-medium text-gray-400 text-right\">Actions</th>\n              </tr>\n            </thead>\n            <tbody>\n              {filtered.map((scan, i) => (\n                <motion.tr \n                  initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: i * 0.05 }}\n                  key={scan.id} className=\"border-b border-border/50 hover:bg-surface/50 transition\"\n                >\n                  <td className=\"p-4 font-mono text-sm\">{scan.target}</td>\n                  <td className=\"p-4 text-gray-400\">{scan.scan_type}</td>\n                  <td className=\"p-4 font-bold\">{scan.risk_score}</td>\n                  <td className=\"p-4\">\n                    <span className={`px-2 py-1 rounded text-xs font-bold ${\n                      scan.risk_level === 'Critical' ? 'bg-danger/20 text-danger' : \n                      scan.risk_level === 'High' ? 'bg-orange-500/20 text-orange-500' : 'bg-success/20 text-success'\n                    }`}>\n                      {scan.risk_level}\n                    </span>\n                  </td>\n                  <td className=\"p-4 text-gray-400 text-sm\">{scan.date.split(' ')[0]}</td>\n                  <td className=\"p-4 flex justify-end gap-3\">\n                    <Link to={`/app/results/${scan.id}`} className=\"text-primary hover:text-primary-light transition flex items-center gap-1 text-sm\">\n                      View <ArrowRight size={14} />\n                    </Link>\n                  </td>\n                </motion.tr>\n              ))}\n              {filtered.length === 0 && (\n                <tr><td colSpan={6} className=\"p-8 text-center text-gray-500\">No scans found.</td></tr>\n              )}\n            </tbody>\n          </table>\n        </div>\n      </div>\n    </div>\n  );\n};\n\nexport default History;\n",
        "frontend/src/App.tsx": "import React from 'react';\nimport { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';\nimport MainLayout from './layouts/MainLayout';\nimport WebsiteScanner from './pages/WebsiteScanner';\nimport QRScanner from './components/scanner/QRScanner';\nimport Results from './pages/Results';\nimport Dashboard from './pages/Dashboard';\nimport History from './pages/History';\nimport AuthContext, { AuthProvider } from './contexts/AuthContext';\nimport Login from './pages/Login';\n\nconst ProtectedRoute = ({ children }: { children: React.ReactNode }) => {\n  const { isAuthenticated, loading } = React.useContext(AuthContext);\n  if (loading) return <div className=\"p-20 text-center\">Loading...</div>;\n  return isAuthenticated ? children : <Navigate to=\"/login\" />;\n};\n\nfunction App() {\n  return (\n    <Router>\n      <AuthProvider>\n        <Routes>\n          <Route path=\"/login\" element={<Login />} />\n          <Route path=\"/\" element={<Navigate to=\"/app/dashboard\" />} />\n          <Route path=\"/app\" element={<ProtectedRoute><MainLayout /></ProtectedRoute>}>\n            <Route path=\"dashboard\" element={<Dashboard />} />\n            <Route path=\"history\" element={<History />} />\n            <Route path=\"scanner\" element={<WebsiteScanner />} />\n            <Route path=\"qr\" element={<QRScanner />} />\n            <Route path=\"results/:id\" element={<Results />} />\n          </Route>\n        </Routes>\n      </AuthProvider>\n    </Router>\n  );\n}\n\nexport default App;\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Stage 13 Analytics Scaffolded.")
